import { useState, useEffect } from "react";
// Double check that your folder is src/services/api.js
import { getTasks, createTask, updateTask, deleteTask } from "../services/api";

export function useTasks() {
  const [tasks, setTasks] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);

  const fetchTasks = async (status) => {
    try {
      setLoading(true);
      setError(null);
      const res = await getTasks(status);
      setTasks(res.data);
    } catch (err) {
      setError("Failed to load tasks. Is the backend running?");
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => { 
    fetchTasks(); 
  }, []);

 const addTask = async (form) => {
  try {
    const res = await createTask(form);
    

    if (res && res.data) {
      setTasks(t => [res.data, ...t]);
    }
  } catch (err) {
    console.error("Form Submission Error:", err);
    setError("Failed to create task.");
  }
};

  const editTask = async (id, form) => {
    try {
      const res = await updateTask(id, form);
      setTasks(t => t.map(tk => tk._id === id ? res.data : tk));
    } catch (err) {
      setError("Failed to update task.");
    }
  };

 const removeTask = async (id) => {
  try {
    await deleteTask(id);
    // FIX: Change tk.id to tk._id to correctly update the UI state
    setTasks(t => t.filter(tk => tk._id !== id));
  } catch (err) {
    setError("Failed to delete task.");
  }
};

  return { tasks, loading, error, addTask, editTask, removeTask, fetchTasks };
}
